func inboxRowClass(msg *message) string {
	if msg.IsUnread() {
		return "list-group-item list-group-item-action py-3"
	}
	return "list-group-item list-group-item-action py-3 text-muted"
}

func boldIfUnread(msg *message) string {
	if msg.IsUnread() {
		return "fw-semibold"
	}
	return ""
}

// formatNumber lightly prettifies +1XXXYYYZZZZ → +1 (XXX) YYY-ZZZZ.
// Falls back to the raw input on any non-North-American format.
func formatNumber(n string) string {
	if len(n) == 12 && n[0] == '+' && n[1] == '1' {
		return fmt.Sprintf("+1 (%s) %s-%s", n[2:5], n[5:8], n[8:12])
	}
	if n == "" {
		return "(unknown)"
	}
	return n
}

